+  if (!process.env.ZAI_API_KEY?.trim() && process.env.Z_AI_API_KEY?.trim()) {
+    process.env.ZAI_API_KEY = process.env.Z_AI_API_KEY;
+  }
+}
+
+export function normalizeEnv(): void {
+  normalizeZaiEnv();
+}

